initScript:
const managerBase = new URL('.', location.href).pathname.replace(/\/$/, '');
const siteApiBase = managerBase + '/api/site';
const dirApiBase = managerBase + '/api/dir';
const fileApiBase = managerBase + '/api/file';
const workspaceRoot = (await utils.postForm(siteApiBase + '/get_root.php', {})).trim().replace(/\/$/, '');
const baseDir = workspaceRoot + '/.temp';
return {
  baseDir,
  transferDirName: 'transfer-box',
  transferInnerFileName: 'inner.txt',
  createDirUrl: dirApiBase + '/create_dir.php',
  scanDirUrl: dirApiBase + '/scan_dir.php',
  scanFileUrl: fileApiBase + '/scan_file.php',
  createFileUrl: fileApiBase + '/create_file.php',
  uploadFilesUrl: fileApiBase + '/upload_files.php',
  downloadDirUrl: dirApiBase + '/download_dir.php',
  message: 'init done'
};

tests.scriptText:
const text = await utils.postForm(createDirUrl, { dir: baseDir, name: transferDirName });
const m = text.match(/\[(.+?)\/\]/);
assert(m && m[1], 'create: parse fail');
const dirs = JSON.parse((await utils.postForm(scanDirUrl, { path: baseDir })) || '[]');
assert(Array.isArray(dirs), 'create: scan dir not array');
assert(dirs.includes(transferDirName), 'create: dir missing');
return { transferDirPath: m[1], message: 'created=' + m[1] };

assert(transferDirPath, 'please run create first');
assert(selectedUploadFile, 'please choose file before run');
await utils.postMultipart(uploadFilesUrl, [selectedUploadFile], [transferDirPath]);
const uploadedSingleFileName = selectedUploadFile.name;
const files = JSON.parse((await utils.postForm(scanFileUrl, { path: transferDirPath })) || '[]');
assert(Array.isArray(files), 'upload_file: scan file not array');
assert(files.includes(uploadedSingleFileName), 'upload_file: uploaded file missing');
return { uploadedSingleFileName, message: 'uploaded=' + uploadedSingleFileName };

assert(transferDirPath, 'please run create first');
assert(Array.isArray(selectedUploadFolderFiles) && selectedUploadFolderFiles.length > 0, 'please choose folder before run');
const dirname = (p) => { const i = String(p || '').lastIndexOf('/'); return i >= 0 ? p.slice(0, i) : ''; };
const dirsParam = selectedUploadFolderFiles.map((f) => {
  const relDir = dirname(f.webkitRelativePath || '');
  return relDir ? `${transferDirPath}/${relDir}` : transferDirPath;
});
await utils.postMultipart(uploadFilesUrl, selectedUploadFolderFiles, dirsParam);
const uploadedFolderTop = (selectedUploadFolderFiles[0].webkitRelativePath || '').split('/')[0] || '';
assert(uploadedFolderTop, 'upload_folder: folder top parse fail');
const dirs = JSON.parse((await utils.postForm(scanDirUrl, { path: transferDirPath })) || '[]');
assert(Array.isArray(dirs), 'upload_folder: scan dir not array');
assert(dirs.includes(uploadedFolderTop), 'upload_folder: folder top missing');
return { uploadedFolderTop, message: 'uploaded folder=' + uploadedFolderTop };

assert(transferDirPath, 'please run create first');
const text = await utils.postForm(createFileUrl, { dir: transferDirPath, name: transferInnerFileName });
const m = text.match(/\[(.+?)\]/);
assert(m && m[1], 'create_inner_file: parse fail');
const files = JSON.parse((await utils.postForm(scanFileUrl, { path: transferDirPath })) || '[]');
assert(Array.isArray(files), 'create_inner_file: scan file not array');
assert(files.includes(transferInnerFileName), 'create_inner_file: file missing');
return { innerFilePath: m[1], message: 'created=' + transferInnerFileName };
